import{_ as t,a as n,b as a,c as r}from"./chunks/下载好后的视频.pSSnkGgz.js";import{_ as d,o as i,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Magnet-Links verwenden","description":"","frontmatter":{},"headers":[],"relativePath":"de-DE/Other/magnet-transfer.md","filePath":"de-DE/Other/magnet-transfer.md","lastUpdated":1781962217000}'),o={name:"de-DE/Other/magnet-transfer.md"};function h(u,e,g,c,b,p){return i(),s("div",null,[...e[0]||(e[0]=[l('<h1 id="magnet-links-verwenden" tabindex="-1">Magnet-Links verwenden <a class="header-anchor" href="#magnet-links-verwenden" aria-label="Permalink to &quot;Magnet-Links verwenden&quot;">​</a></h1><p>Mit der Magnet-Funktion lädt ImgBed Dateien aus einem Magnet-Link herunter und lädt sie anschließend automatisch in den gewählten Speicherkanal hoch.</p><p>Das eignet sich für Videos, Serienfolgen, Archive und ähnliche Dateien. Du fügst nur den Magnet-Link ein; ImgBed erstellt im Hintergrund eine Aufgabe und zeigt nach Abschluss den fertigen Link in der Upload-Liste.</p><p><img src="'+t+'" alt="Magnet-Link" loading="lazy"></p><h2 id="wo-verwenden" tabindex="-1">Wo verwenden <a class="header-anchor" href="#wo-verwenden" aria-label="Permalink to &quot;Wo verwenden&quot;">​</a></h2><p>Die Eingabe befindet sich im Upload-Bereich der Startseite.</p><p>Füge den Magnet-Link in das Feld ein, wähle den Modus <code>Übertragen</code> und starte den Upload.</p><p><img src="'+n+'" alt="Magnet übertragen" loading="lazy"></p><h2 id="vor-der-ersten-nutzung" tabindex="-1">Vor der ersten Nutzung <a class="header-anchor" href="#vor-der-ersten-nutzung" aria-label="Permalink to &quot;Vor der ersten Nutzung&quot;">​</a></h2><p>Richte zuerst die Magnet-Übertragung im Adminbereich ein.</p><p>Üblicherweise brauchst du:</p><table tabindex="0"><thead><tr><th>Voraussetzung</th><th>Zweck</th></tr></thead><tbody><tr><td>GitHub-Konto</td><td>Führt die Download-Aufgabe aus</td></tr><tr><td>Upload-Kanal</td><td>Ziel wie Google Drive, OneDrive oder ein anderer Speicher</td></tr><tr><td>Zielordner</td><td>Ordner, in dem die übertragene Datei landet</td></tr><tr><td>Zeitlimit</td><td>Grenze für lange Aufgaben</td></tr></tbody></table><h2 id="magnet-ubertragen" tabindex="-1">Magnet übertragen <a class="header-anchor" href="#magnet-ubertragen" aria-label="Permalink to &quot;Magnet übertragen&quot;">​</a></h2><ol><li>Füge den Magnet-Link in das Upload-Feld ein.</li><li>Prüfe, dass der Modus <code>Übertragen</code> gewählt ist.</li><li>Klicke auf Upload.</li><li>Warte, bis ImgBed die Aufgabe erstellt.</li><li>Verfolge den Fortschritt im Fenster <code>Magnet-Aufgaben</code> unten rechts.</li></ol><p>Download und Upload können dauern. Die Geschwindigkeit hängt von der Verfügbarkeit des Magnets, der GitHub-Ausführungsumgebung und dem gewählten Speicherkanal ab.</p><p><img src="'+a+'" alt="Download läuft" loading="lazy"></p><h2 id="nach-abschluss" tabindex="-1">Nach Abschluss <a class="header-anchor" href="#nach-abschluss" aria-label="Permalink to &quot;Nach Abschluss&quot;">​</a></h2><p>Nach Abschluss zeigt die Upload-Liste Dateiname und Links.</p><p>Videos erhalten eine Videovorschau, Bilder eine Bildvorschau, andere Dateien ein normales Dateisymbol.</p><p><img src="'+r+'" alt="Übertragenes Video" loading="lazy"></p><p>Diese Formate kannst du kopieren:</p><table tabindex="0"><thead><tr><th>Format</th><th>Verwendung</th></tr></thead><tbody><tr><td>Originallink</td><td>Datei direkt öffnen</td></tr><tr><td>Markdown</td><td>In Markdown-Beiträge oder Dokumentation einfügen</td></tr><tr><td>HTML</td><td>In Webseitencode einfügen</td></tr><tr><td>BBCode</td><td>In Foren mit BBCode-Unterstützung verwenden</td></tr></tbody></table><h2 id="aufgabenstatus" tabindex="-1">Aufgabenstatus <a class="header-anchor" href="#aufgabenstatus" aria-label="Permalink to &quot;Aufgabenstatus&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Status</th><th>Bedeutung</th></tr></thead><tbody><tr><td>Wartend</td><td>Aufgabe wurde erstellt und wartet auf Ausführung</td></tr><tr><td>Lädt herunter</td><td>Magnet-Ressource wird heruntergeladen</td></tr><tr><td>Lädt hoch</td><td>Datei wurde geladen und wird in den Kanal hochgeladen</td></tr><tr><td>Abgeschlossen</td><td>Upload ist fertig, Link kann kopiert werden</td></tr><tr><td>Fehlgeschlagen</td><td>Hinweis prüfen und erneut versuchen</td></tr></tbody></table><h2 id="hinweise" tabindex="-1">Hinweise <a class="header-anchor" href="#hinweise" aria-label="Permalink to &quot;Hinweise&quot;">​</a></h2><ul><li>Enthält ein Magnet mehrere Dateien, zeigt ImgBed bevorzugt die wichtigste abgeschlossene Datei.</li><li>Große Dateien brauchen mehr Zeit; lade die Seite erst nach Abschluss neu.</li><li>Hat die Ressource keine verfügbaren Quellen, kann der Download sehr langsam sein oder scheitern.</li><li>Fehlende Quota, abgelaufene Berechtigungen oder falsche Zielordner können den Upload ebenfalls scheitern lassen.</li><li>Videovorschauen benötigen manchmal ein paar Sekunden.</li></ul>',26)])])}const w=d(o,[["render",h]]);export{k as __pageData,w as default};
